import { AppDataSource } from '../../config/database';
import { RouteStatus, TradingRoute } from '../../models/TradingRoute';
import {
  CreateRouteInput,
  ListOrgRoutesParams,
  TradingRouteService,
} from '../../services/trade/TradingRouteService';
import { ConflictError, NotFoundError } from '../../utils/apiErrors';

jest.mock('../../config/database', () => ({
  AppDataSource: { getRepository: jest.fn() },
}));

jest.mock('../../services/trade/trading/UEXPriceFeed', () => ({
  UEXPriceFeed: jest.fn().mockImplementation(() => ({
    calculateRouteProfit: jest.fn().mockResolvedValue(12500),
  })),
}));

jest.mock('../../websocket/controllers/tradingWebSocketController', () => ({
  emitRouteCreated: jest.fn(),
  emitRouteUpdated: jest.fn(),
  emitRouteDeleted: jest.fn(),
  emitRouteStatusChanged: jest.fn(),
}));

jest.mock('../../utils/logger', () => ({
  logger: { info: jest.fn(), error: jest.fn(), warn: jest.fn(), debug: jest.fn() },
}));

// ─── helpers ─────────────────────────────────────────────────────────────────

function makeRoute(overrides: Partial<TradingRoute> = {}): TradingRoute {
  return {
    id: 'route-1',
    organizationId: 'org-1',
    name: 'Test Route',
    description: '',
    status: RouteStatus.ACTIVE,
    stops: [],
    tags: [],
    performance: { runCount: 0, avgProfit: 0, avgDuration: 0 },
    estimatedProfit: 0,
    estimatedDuration: undefined,
    minCargoCapacity: undefined,
    creatorId: 'user-1',
    notes: undefined,
    createdAt: new Date(),
    updatedAt: new Date(),
    ...overrides,
  } as unknown as TradingRoute;
}

function makeQueryBuilder(overrides: Record<string, jest.Mock> = {}): Record<string, jest.Mock> {
  const qb: Record<string, jest.Mock> = {
    where: jest.fn().mockReturnThis(),
    andWhere: jest.fn().mockReturnThis(),
    orderBy: jest.fn().mockReturnThis(),
    skip: jest.fn().mockReturnThis(),
    take: jest.fn().mockReturnThis(),
    getOne: jest.fn().mockResolvedValue(null),
    getMany: jest.fn().mockResolvedValue([]),
    getCount: jest.fn().mockResolvedValue(0),
    ...overrides,
  };
  // Each chainable call returns the same builder
  qb.where.mockReturnValue(qb);
  qb.andWhere.mockReturnValue(qb);
  qb.orderBy.mockReturnValue(qb);
  qb.skip.mockReturnValue(qb);
  qb.take.mockReturnValue(qb);
  return qb;
}

// ─── suite ───────────────────────────────────────────────────────────────────

describe('TradingRouteService', () => {
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  let mockRepo: Record<string, jest.Mock>;
  let service: TradingRouteService;

  beforeEach(() => {
    jest.clearAllMocks();

    mockRepo = {
      createQueryBuilder: jest.fn(() => makeQueryBuilder()),
      create: jest.fn((data: Partial<TradingRoute>) => data as TradingRoute),
      save: jest.fn(async (entity: TradingRoute) => entity),
      remove: jest.fn().mockResolvedValue(undefined),
    };

    (AppDataSource.getRepository as jest.Mock).mockReturnValue(mockRepo);

    const { UEXPriceFeed } = jest.requireMock('../../services/trade/trading/UEXPriceFeed');
    service = new TradingRouteService(new UEXPriceFeed());
  });

  // ── findById ──────────────────────────────────────────────────────────────

  describe('findById', () => {
    it('should return a route when found', async () => {
      const route = makeRoute();
      const qb = makeQueryBuilder({ getOne: jest.fn().mockResolvedValue(route) });
      mockRepo.createQueryBuilder.mockReturnValue(qb);

      const result = await service.findById('route-1');
      expect(result).toBe(route);
    });

    it('should return null when not found', async () => {
      const result = await service.findById('missing');
      expect(result).toBeNull();
    });

    it('should scope by organizationId when provided', async () => {
      const qb = makeQueryBuilder();
      mockRepo.createQueryBuilder.mockReturnValue(qb);

      await service.findById('route-1', 'org-1');
      expect(qb.andWhere).toHaveBeenCalledWith('route.organizationId = :organizationId', {
        organizationId: 'org-1',
      });
    });
  });

  // ── listOrgRoutes ─────────────────────────────────────────────────────────

  describe('listOrgRoutes', () => {
    const defaultParams: ListOrgRoutesParams = {
      limit: 20,
      offset: 0,
      sort: null,
      filters: {},
      search: null,
      fields: null,
    };

    it('should return paginated routes', async () => {
      const routes = [makeRoute()];
      const qb = makeQueryBuilder({
        getCount: jest.fn().mockResolvedValue(1),
        getMany: jest.fn().mockResolvedValue(routes),
      });
      mockRepo.createQueryBuilder.mockReturnValue(qb);

      const result = await service.listOrgRoutes('org-1', defaultParams);
      expect(result.routes).toBe(routes);
      expect(result.total).toBe(1);
    });

    it('should apply status filter when provided', async () => {
      const qb = makeQueryBuilder();
      mockRepo.createQueryBuilder.mockReturnValue(qb);

      await service.listOrgRoutes('org-1', { ...defaultParams, filters: { status: 'active' } });
      expect(qb.andWhere).toHaveBeenCalledWith('route.status = :status', { status: 'active' });
    });

    it('should apply search filter when provided', async () => {
      const qb = makeQueryBuilder();
      mockRepo.createQueryBuilder.mockReturnValue(qb);

      await service.listOrgRoutes('org-1', { ...defaultParams, search: 'cargo' });
      expect(qb.andWhere).toHaveBeenCalledWith(
        '(route.name ILIKE :search OR route.description ILIKE :search)',
        { search: '%cargo%' }
      );
    });

    it('should apply explicit sort when provided', async () => {
      const qb = makeQueryBuilder();
      mockRepo.createQueryBuilder.mockReturnValue(qb);

      await service.listOrgRoutes('org-1', {
        ...defaultParams,
        sort: { field: 'name', order: 'ASC' },
      });
      expect(qb.orderBy).toHaveBeenCalledWith('route.name', 'ASC');
    });
  });

  // ── createRoute ───────────────────────────────────────────────────────────

  describe('createRoute', () => {
    const input: CreateRouteInput = {
      name: 'New Route',
      description: 'desc',
      stops: [],
      tags: [],
    };

    it('should create and return a route', async () => {
      const saved = makeRoute({ name: 'New Route' });
      mockRepo.save.mockResolvedValue(saved);

      const result = await service.createRoute('org-1', 'user-1', input);
      expect(mockRepo.save).toHaveBeenCalled();
      expect(result).toBe(saved);
    });

    it('should throw ConflictError when route name already exists', async () => {
      const existing = makeRoute();
      const qb = makeQueryBuilder({ getOne: jest.fn().mockResolvedValue(existing) });
      mockRepo.createQueryBuilder.mockReturnValue(qb);

      await expect(service.createRoute('org-1', 'user-1', input)).rejects.toBeInstanceOf(
        ConflictError
      );
    });
  });

  // ── updateRoute ───────────────────────────────────────────────────────────

  describe('updateRoute', () => {
    it('should update and return the route', async () => {
      const route = makeRoute();
      const qb = makeQueryBuilder({ getOne: jest.fn().mockResolvedValue(route) });
      mockRepo.createQueryBuilder.mockReturnValue(qb);

      const result = await service.updateRoute('route-1', 'org-1', { name: 'Updated' });
      expect(result.route.name).toBe('Updated');
      expect(mockRepo.save).toHaveBeenCalledWith(route);
    });

    it('should detect status change', async () => {
      const route = makeRoute({ status: RouteStatus.ACTIVE });
      const qb = makeQueryBuilder({ getOne: jest.fn().mockResolvedValue(route) });
      mockRepo.createQueryBuilder.mockReturnValue(qb);

      const result = await service.updateRoute('route-1', 'org-1', {
        status: RouteStatus.INACTIVE,
      });
      expect(result.statusChanged).toBe(true);
      expect(result.oldStatus).toBe(RouteStatus.ACTIVE);
    });

    it('should throw NotFoundError when route does not exist', async () => {
      await expect(service.updateRoute('missing', 'org-1', {})).rejects.toBeInstanceOf(
        NotFoundError
      );
    });

    it('should throw NotFoundError when route belongs to different org', async () => {
      const route = makeRoute({ organizationId: 'other-org' });
      const qb = makeQueryBuilder({ getOne: jest.fn().mockResolvedValue(route) });
      mockRepo.createQueryBuilder.mockReturnValue(qb);

      await expect(service.updateRoute('route-1', 'org-1', {})).rejects.toBeInstanceOf(
        NotFoundError
      );
    });
  });

  // ── deleteRoute ───────────────────────────────────────────────────────────

  describe('deleteRoute', () => {
    it('should remove the route and not throw', async () => {
      const route = makeRoute();
      const qb = makeQueryBuilder({ getOne: jest.fn().mockResolvedValue(route) });
      mockRepo.createQueryBuilder.mockReturnValue(qb);

      await expect(service.deleteRoute('route-1', 'org-1')).resolves.toBeUndefined();
      expect(mockRepo.remove).toHaveBeenCalledWith(route);
    });

    it('should throw NotFoundError when route does not exist', async () => {
      await expect(service.deleteRoute('missing', 'org-1')).rejects.toBeInstanceOf(NotFoundError);
    });

    it('should throw NotFoundError when route belongs to different org', async () => {
      const route = makeRoute({ organizationId: 'other-org' });
      const qb = makeQueryBuilder({ getOne: jest.fn().mockResolvedValue(route) });
      mockRepo.createQueryBuilder.mockReturnValue(qb);

      await expect(service.deleteRoute('route-1', 'org-1')).rejects.toBeInstanceOf(NotFoundError);
    });
  });

  // ── calculateRouteRating ──────────────────────────────────────────────────

  describe('calculateRouteRating', () => {
    it('should return 0 for a route with no data', () => {
      const route = makeRoute({
        estimatedProfit: 0,
        estimatedDuration: undefined,
        performance: { runCount: 0, avgProfit: 0, avgDuration: 0 },
      });
      expect(service.calculateRouteRating(route)).toBe(0);
    });

    it('should cap rating at 10', () => {
      const route = makeRoute({
        estimatedProfit: 1_000_000,
        estimatedDuration: 1,
        performance: { runCount: 1000, avgProfit: 500000, avgDuration: 1 },
      });
      expect(service.calculateRouteRating(route)).toBe(10);
    });

    it('should increase rating with higher profit', () => {
      const low = makeRoute({ estimatedProfit: 5000 });
      const high = makeRoute({ estimatedProfit: 40000 });
      expect(service.calculateRouteRating(high)).toBeGreaterThan(service.calculateRouteRating(low));
    });
  });
});
